1	import { useEngineStats } from "@/lib/query/hooks";
2	import type { EngineStatsResponse, CliqueSummary } from "@/lib/api/types";
3	
4	interface JunctionTreePanelProps {
5	  marketId: string;
6	}
7	
8	function CliqueCard({ clique, maxStates }: { clique: CliqueSummary; maxStates: number }) {
9	  const barPct = maxStates > 0 ? (clique.states / maxStates) * 100 : 0;
10	
11	  return (
12	    <div style={cliqueCardStyle}>
13	      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", marginBottom: 4 }}>
14	        <span style={{ fontSize: "0.8rem", fontWeight: 600, fontFamily: "var(--font-mono)" }}>
15	          {clique.id}
16	        </span>
17	        <span style={{ fontSize: "0.7rem", color: "var(--color-text-muted)" }}>
18	          {clique.size} vars · {clique.states.toLocaleString()} states
19	        </span>
20	      </div>
21	      <div style={{ display: "flex", flexWrap: "wrap", gap: 4, marginBottom: 6 }}>
22	        {clique.nodes.map((n) => (
23	          <span key={n} style={varTagStyle}>{n}</span>
24	        ))}
25	      </div>
26	      <div style={{ height: 6, borderRadius: 3, background: "var(--color-border)", overflow: "hidden" }}>
27	        <div
28	          style={{
29	            height: "100%",
30	            width: `${barPct}%`,
31	            borderRadius: 3,
32	            background: barPct > 80 ? "var(--color-danger)" : barPct > 50 ? "var(--color-warning, orange)" : "var(--color-success)",
33	            transition: "width 0.3s ease",
34	          }}
35	        />
36	      </div>
37	    </div>
38	  );
39	}
40	
41	function InferenceDiagnostics({ stats }: { stats: EngineStatsResponse }) {
42	  const d = stats.diagnostics;
43	  const inf = d.inference;
44	  const cache = d.cache;
45	  const hasLatency = (inf.sample_count ?? 0) > 0;
46	
47	  return (
48	    <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(140px, 1fr))", gap: "var(--space-sm)" }}>
49	      <MetricBox label="Requests" value={d.request_count.toLocaleString()} />
50	      <MetricBox label="Errors" value={d.error_count.toLocaleString()} warn={d.error_count > 0} />
51	      <MetricBox
52	        label="Cache Hit Rate"
53	        value={cache.hits + cache.misses > 0 ? `${(cache.hit_rate * 100).toFixed(1)}%` : "—"}
54	        sub={`${cache.hits} / ${cache.hits + cache.misses}`}
55	      />
56	      {hasLatency && (
57	        <>
58	          <MetricBox label="p50 Latency" value={`${inf.p50_ms.toFixed(1)}ms`} />
59	          <MetricBox label="p95 Latency" value={`${inf.p95_ms.toFixed(1)}ms`} />
60	          <MetricBox label="p99 Latency" value={`${inf.p99_ms.toFixed(1)}ms`} />
61	        </>
62	      )}
63	      {d.compile_time_ms != null && (
64	        <MetricBox label="Compile Time" value={`${d.compile_time_ms.toFixed(0)}ms`} />
65	      )}
66	      {d.memory_bytes != null && (
67	        <MetricBox label="Memory" value={formatBytes(d.memory_bytes)} />
68	      )}
69	    </div>
70	  );
71	}
72	
73	function MetricBox({ label, value, sub, warn }: { label: string; value: string; sub?: string; warn?: boolean }) {
74	  return (
75	    <div style={metricBoxStyle}>
76	      <div style={{ fontSize: "0.7rem", color: "var(--color-text-muted)", marginBottom: 2 }}>{label}</div>
77	      <div style={{ fontSize: "1.1rem", fontWeight: 700, fontFamily: "var(--font-mono)", color: warn ? "var(--color-danger)" : "var(--color-text)" }}>
78	        {value}
79	      </div>
80	      {sub && <div style={{ fontSize: "0.65rem", color: "var(--color-text-muted)" }}>{sub}</div>}
81	    </div>
82	  );
83	}
84	
85	function formatBytes(bytes: number): string {
86	  if (bytes < 1024) return `${bytes}B`;
87	  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)}KB`;
88	  return `${(bytes / (1024 * 1024)).toFixed(1)}MB`;
89	}
90	
91	export function JunctionTreePanel({ marketId }: JunctionTreePanelProps) {
92	  const { data, isLoading } = useEngineStats(marketId);
93	
94	  if (isLoading) {
95	    return (
96	      <div style={panelStyle}>
97	        <div style={{ color: "var(--color-text-muted)", textAlign: "center" }}>Loading engine stats...</div>
98	      </div>
99	    );
100	  }
101	
102	  if (!data) return null;
103	
104	  const { engine, cliques, diagnostics } = data;
105	  const maxStates = Math.max(1, ...cliques.cliques.map((c) => c.states));
106	  const hasCliques = cliques.cliques.length > 0;
107	
108	  return (
109	    <div style={panelStyle}>
110	      <h3 style={{ fontSize: "1rem", fontWeight: 600, marginBottom: "var(--space-sm)" }}>
111	        Junction Tree & Inference
112	      </h3>
113	
114	      {/* Engine info banner */}
115	      <div style={engineBannerStyle}>
116	        <span><strong>Engine:</strong> {engine.mode} / {engine.backend} v{engine.version}</span>
117	        <span><strong>Precision:</strong> {engine.precision}</span>
118	        {engine.compile_id && <span><strong>Compiled:</strong> {engine.compile_id.slice(0, 12)}</span>}
119	        {engine.source_state_hash && <span><strong>State:</strong> {engine.source_state_hash.slice(0, 12)}</span>}
120	      </div>
121	
122	      {/* Junction tree summary */}
123	      <div style={{ marginTop: "var(--space-md)" }}>
124	        <div style={{ display: "flex", gap: "var(--space-lg)", marginBottom: "var(--space-sm)" }}>
125	          <div>
126	            <span style={{ fontSize: "0.75rem", color: "var(--color-text-muted)" }}>Cliques</span>
127	            <div style={{ fontSize: "1.5rem", fontWeight: 700, fontFamily: "var(--font-mono)" }}>
128	              {cliques.num_cliques}
129	            </div>
130	          </div>
131	          <div>
132	            <span style={{ fontSize: "0.75rem", color: "var(--color-text-muted)" }}>Max Clique Size</span>
133	            <div style={{ fontSize: "1.5rem", fontWeight: 700, fontFamily: "var(--font-mono)" }}>
134	              {cliques.max_clique_size}
135	            </div>
136	          </div>
137	          <div>
138	            <span style={{ fontSize: "0.75rem", color: "var(--color-text-muted)" }}>Tree Width</span>
139	            <div style={{ fontSize: "1.5rem", fontWeight: 700, fontFamily: "var(--font-mono)" }}>
140	              {cliques.junction_tree_width}
141	            </div>
142	          </div>
143	        </div>
144	
145	        {hasCliques ? (
146	          <div style={{ display: "grid", gap: "var(--space-sm)" }}>
147	            {cliques.cliques.map((c) => (
148	              <CliqueCard key={c.id} clique={c} maxStates={maxStates} />
149	            ))}
150	          </div>
151	        ) : (
152	          <div style={emptyCliqueStyle}>
153	            No cliques yet — market has independent variables or hasn't been compiled.
154	            Submit conditional edits to create dependencies between variables.
155	          </div>
156	        )}
157	      </div>
158	
159	      {/* Inference diagnostics */}
160	      <div style={{ marginTop: "var(--space-md)" }}>
161	        <h4 style={{ fontSize: "0.9rem", fontWeight: 600, marginBottom: "var(--space-sm)" }}>
162	          Inference Diagnostics
163	        </h4>
164	        <InferenceDiagnostics stats={data} />
165	        {diagnostics.last_updated && (
166	          <div style={{ fontSize: "0.65rem", color: "var(--color-text-muted)", marginTop: "var(--space-xs)" }}>
167	            Last updated: {new Date(diagnostics.last_updated).toLocaleString()}
168	          </div>
169	        )}
170	      </div>
171	    </div>
172	  );
173	}
