33	    marketId,
34	    comments: [],
35	    pagination: {
36	      fromSeq: 0,
37	      limit: 0,
38	      returned: 0,
39	      nextFromSeq: null,
40	    },
41	    meta: {
42	      apiVersion: "unknown",
43	      timestamp: "1970-01-01T00:00:00.000Z",
44	    },
45	  };
